class FocalLoss(torch.nn.Module):
    def __init__(self, num_classes, alpha=1.0, gamma=2.0):
        super(FocalLoss, self).__init__()
        self.num_classes = num_classes
        self.alpha = alpha
        self.gamma = gamma
    def forward(self, logits, target):
        pred = F.softmax(logits, dim=-1)  # Convert logits to probabilities
        true_class_pred = pred.gather(1, target.unsqueeze(1)).squeeze(1)  # Extract probabilities for the true class
        focal_weight = ((1 - true_class_pred) ** self.gamma) * self.alpha  # Compute focal weight

